1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteContext = {
9	  yearsWithMHPCO: number;
10	  isFollowUp: boolean;
11	};
12	
13	const POLICY_FEE = 5;
14	
15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	  rune: 25,
21	  moonstone: 25,
22	};
23	
24	const BLOCK_SIZE = 3;
25	const BLOCK_PRICE = 60;
26	
27	const COMPONENT_TYPES = ["rune", "moonstone"];
28	
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
33	
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	
36	const CURSE_SURCHARGE_RATE = 0.5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	const HIGH_ENCHANTMENT_THRESHOLD = 5;
39	
40	const isComponent = (item: Item): boolean =>
41	  COMPONENT_TYPES.includes(item.type);
42	
43	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
44	
45	const itemSpecificSurcharges = (item: Item): number => {
46	  const base = basePremiumFor(item);
47	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
48	  const isHighEnchantment = item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
49	  const highEnchantmentSurcharge = isHighEnchantment ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
50	  return curseSurcharge + highEnchantmentSurcharge;
51	};
52	
53	const componentGroupPremium = (type: string, count: number): number =>
54	  count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUM[type];
55	
56	const loyaltyDiscountFor = (policyBasePremium: number, context: QuoteContext): number =>
57	  context.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? policyBasePremium * LOYALTY_DISCOUNT_RATE : 0;
58	
59	const firstInsuranceSurchargeFor = (policyBasePremium: number): number =>
60	  policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
61	
62	const followUpDiscountFor = (policyBasePremium: number, context: QuoteContext): number =>
63	  context.isFollowUp ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
64	
65	const assertKnownItemTypes = (items: Item[]): void => {
66	  for (const item of items) {
67	    if (!(item.type in BASE_PREMIUM)) {
68	      throw new Error(`Unknown item type: ${item.type}`);
69	    }
70	  }
71	};
72	
73	export function quote(items: Item[], context: QuoteContext): number {
74	  assertKnownItemTypes(items);
75	
76	  const componentBasePremium = COMPONENT_TYPES.reduce((sum, type) => {
77	    const count = items.filter((item) => item.type === type).length;
78	    return sum + componentGroupPremium(type, count);
79	  }, 0);
80	
81	  const mainItemsBasePremium = items
82	    .filter((item) => !isComponent(item))
83	    .reduce((sum, item) => sum + basePremiumFor(item), 0);
84	
85	  const unmodifiedBaseTotal = mainItemsBasePremium + componentBasePremium;
86	
87	  const itemSpecificSurchargesTotal = items.reduce(
88	    (sum, item) => sum + itemSpecificSurcharges(item),
89	    0
90	  );
91	
92	  const policyDiscounts =
93	    loyaltyDiscountFor(unmodifiedBaseTotal, context) +
94	    followUpDiscountFor(unmodifiedBaseTotal, context);
95	  const policySurcharges = firstInsuranceSurchargeFor(unmodifiedBaseTotal);
96	
97	  const premium =
98	    unmodifiedBaseTotal +
99	    itemSpecificSurchargesTotal +
100	    policySurcharges -
101	    policyDiscounts +
102	    POLICY_FEE;
103	
104	  return Math.ceil(premium);
105	}
106	
107	export type Damage = {
108	  itemType: string;
109	  amount: number;
110	};
111	
112	export type Incident = {
113	  cause: string;
114	  damages: Damage[];
115	};
116	
117	export type ClaimResult = {
118	  payout: number;
119	  remainingCap: number;
120	};
121	
122	const INSURANCE_VALUE: Record<string, number> = {
123	  sword: 1000,
124	  amulet: 600,
125	  staff: 800,
126	  potion: 400,
127	  rune: 250,
128	  moonstone: 250,
129	};
130	
131	const DEDUCTIBLE = 100;
132	
133	const CAP_MULTIPLIER = 2;
134	
135	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
136	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
137	
138	const FULL_REIMBURSEMENT_RATE = 1;
139	
140	const reimbursementRateFor = (item: Item): number => {
141	  const isHighEnchantment =
142	    item.enchantment !== undefined &&
143	    item.enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
144	  return isHighEnchantment
145	    ? HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
146	    : FULL_REIMBURSEMENT_RATE;
147	};
148	
149	const insuredItemFor = (policy: Item[], damage: Damage): Item => {
150	  const item = policy.find((item) => item.type === damage.itemType);
151	  if (item === undefined) {
152	    throw new Error(`Damage references item not in policy: ${damage.itemType}`);
153	  }
154	  return item;
155	};
156	
157	const payoutForDamage = (policy: Item[], damage: Damage): number => {
158	  const item = insuredItemFor(policy, damage);
159	  return damage.amount * reimbursementRateFor(item) - DEDUCTIBLE;
160	};
161	
162	const insuranceSumFor = (policy: Item[]): number =>
163	  policy.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
164	
165	const fullCapFor = (policy: Item[]): number =>
166	  CAP_MULTIPLIER * insuranceSumFor(policy);
167	
168	const assertDamageCountsWithinPolicy = (
169	  policy: Item[],
170	  incident: Incident
171	): void => {
172	  for (const damage of incident.damages) {
173	    const insuredCount = policy.filter(
174	      (item) => item.type === damage.itemType
175	    ).length;
176	    const damageCount = incident.damages.filter(
177	      (d) => d.itemType === damage.itemType
178	    ).length;
179	    if (damageCount > insuredCount) {
180	      throw new Error(
181	        `More ${damage.itemType} damages than insured: ${damageCount} > ${insuredCount}`
182	      );
183	    }
184	  }
185	};
186	
187	export function claim(
188	  policy: Item[],
189	  incident: Incident,
190	  remainingCapBefore: number = fullCapFor(policy)
191	): ClaimResult {
192	  assertDamageCountsWithinPolicy(policy, incident);
193	
194	  const rawPayout = incident.damages.reduce(
195	    (sum, damage) => sum + payoutForDamage(policy, damage),
196	    0
197	  );
198	
199	  const payout = Math.floor(Math.min(rawPayout, remainingCapBefore));
200	  const remainingCap = remainingCapBefore - payout;
201	
202	  return { payout, remainingCap };
203	}
